     1вҶ’/*
     2вҶ’ * ESP32 Triple Rotary Encoder Reader - with Position Memory
     3вҶ’ * ==========================================================
     4вҶ’ * Autonics мҰқл¶„нҳ• м—”мҪ”лҚ” 1~3к°ң лҸҷмӢң мқҪкё° (мң м—°н•ң кө¬м„ұ)
     5вҶ’ * + м ҲлҢҖк°’ мӣҗм җ м„Өм • л°Ҹ мң„м№ҳ м ҖмһҘ кё°лҠҘ (NVS мӮ¬мҡ©)
     6вҶ’ * 
     7вҶ’ * кё°лҠҘ:
     8вҶ’ * - мҝјл“ңлҹ¬мІҳ л””мҪ”л”© (4л°° н•ҙмғҒлҸ„)
     9вҶ’ * - мӢӨмӢңк°„ к°ҒлҸ„ кі„мӮ° (0~360лҸ„)
    10вҶ’ * - JSON н”„лЎңнҶ мҪңлЎң PC м „мҶЎ
    11вҶ’ * - м ңлЎң(мӣҗм җ) лҰ¬м…Ӣ лӘ…л № м§Җмӣҗ
    12вҶ’ * - вҳ… м ҲлҢҖк°’ мӣҗм җ м ҖмһҘ (м „мӣҗ кәјм ёлҸ„ мң м§Җ)
    13вҶ’ * - вҳ… мң„м№ҳ 1~100 м ҖмһҘ/л¶Ҳлҹ¬мҳӨкё°/мӮӯм ң/мһ¬м •л ¬
    14вҶ’ * - вҳ… 1~3к°ң м—”мҪ”лҚ” мң м—°н•ҳкІҢ м§Җмӣҗ (м—ҶлҠ” м—”мҪ”лҚ”лҠ” мһҗлҸҷ л№„нҷңм„ұнҷ”)
    15вҶ’ * 
    16вҶ’ * лӘ…л №м–ҙ:
    17вҶ’ * - SAVE n: нҳ„мһ¬ мң„м№ҳлҘј nлІҲм—җ м ҖмһҘ
    18вҶ’ * - SAVEAT n e1 e2 e3: м§Җм •лҗң к°’мқ„ nлІҲм—җ м ҖмһҘ (мһ¬м •л ¬мҡ©)
    19вҶ’ * - DELETE n: nлІҲ мң„м№ҳ мӮӯм ң
    20вҶ’ * - CLEAR: лӘЁл“  мң„м№ҳ мӮӯм ң
    21вҶ’ * - GETALL: лӘЁл“  мң„м№ҳ мЎ°нҡҢ
    22вҶ’ * - ENABLE n: nлІҲ м—”мҪ”лҚ” нҷңм„ұнҷ” (1~3)
    23вҶ’ * - DISABLE n: nлІҲ м—”мҪ”лҚ” л№„нҷңм„ұнҷ” (1~3)
    24вҶ’ * 
    25вҶ’ * мһ‘м„ұмқј: 2024
    26вҶ’ */
    27вҶ’
    28вҶ’#include <Arduino.h>
    29вҶ’#include <Preferences.h>  // ESP32 NVS (л№„нңҳл°ңм„ұ м ҖмһҘмҶҢ)
    30вҶ’
    31вҶ’// ============================================================
    32вҶ’// н•Җ м„Өм • (мүҪкІҢ ліҖкІҪ к°ҖлҠҘн•ҳлҸ„лЎқ мғҒмҲҳлЎң л¶„лҰ¬)
    33вҶ’// ============================================================
    34вҶ’#define ENC1_PIN_A    34    // Encoder 1 - A мӢ нҳё
    35вҶ’#define ENC1_PIN_B    35    // Encoder 1 - B мӢ нҳё
    36вҶ’#define ENC1_PIN_Z    32    // Encoder 1 - Z мӢ нҳё (мҳөм…ҳ)
    37вҶ’
    38вҶ’#define ENC2_PIN_A    36    // Encoder 2 - A мӢ нҳё
    39вҶ’#define ENC2_PIN_B    39    // Encoder 2 - B мӢ нҳё
    40вҶ’#define ENC2_PIN_Z    33    // Encoder 2 - Z мӢ нҳё (мҳөм…ҳ)
    41вҶ’
    42вҶ’#define ENC3_PIN_A    25    // Encoder 3 - A мӢ нҳё
    43вҶ’#define ENC3_PIN_B    26    // Encoder 3 - B мӢ нҳё
    44вҶ’#define ENC3_PIN_Z    27    // Encoder 3 - Z мӢ нҳё (мҳөм…ҳ)
    45вҶ’
    46вҶ’// ============================================================
    47вҶ’// м—”мҪ”лҚ” м„Өм •
    48вҶ’// ============================================================
    49вҶ’#define ENCODER_PPR         100     // м—”мҪ”лҚ” PPR (Pulses Per Revolution)
    50вҶ’#define QUADRATURE_MULT     4       // мҝјл“ңлҹ¬мІҳ 4л°°
    51вҶ’#define COUNTS_PER_REV      (ENCODER_PPR * QUADRATURE_MULT)  // мҙқ м№ҙмҡҙнҠё/нҡҢм „
    52вҶ’#define MAX_ENCODERS        3       // мөңлҢҖ м—”мҪ”лҚ” мҲҳ
    53вҶ’
    54вҶ’// ============================================================
    55вҶ’// нҶөмӢ  м„Өм •
    56вҶ’// ============================================================
    57вҶ’#define SERIAL_BAUD         921600  // кі мҶҚ нҶөмӢ 
    58вҶ’#define UPDATE_INTERVAL_MS  10      // м—…лҚ°мқҙнҠё мЈјкё° (10ms = 100Hz)
    59вҶ’
    60вҶ’// ============================================================
    61вҶ’// мң„м№ҳ м ҖмһҘ м„Өм •
    62вҶ’// ============================================================
    63вҶ’#define MAX_POSITIONS       100     // м ҖмһҘ к°ҖлҠҘн•ң мң„м№ҳ к°ңмҲҳ
    64вҶ’
    65вҶ’// ============================================================
    66вҶ’// кіөм°Ё м„Өм •
    67вҶ’// ============================================================
    68вҶ’int position_tolerance = 5;         // мң„м№ҳ н—Ҳмҡ© мҳӨм°Ё (м№ҙмҡҙнҠё, ліҖкІҪ к°ҖлҠҘ)
    69вҶ’
    70вҶ’// ============================================================
    71вҶ’// кёҖлЎңлІҢ ліҖмҲҳ (volatile: мқён„°лҹҪнҠём—җм„ң мӮ¬мҡ©)
    72вҶ’// ============================================================
    73вҶ’volatile int32_t enc1_count = 0;
    74вҶ’volatile int32_t enc2_count = 0;
    75вҶ’volatile int32_t enc3_count = 0;
    76вҶ’
    77вҶ’// л§Ҳм§Җл§ү мғҒнғң м ҖмһҘ (мҝјл“ңлҹ¬мІҳ л””мҪ”л”©мҡ©)
    78вҶ’volatile uint8_t enc1_last_state = 0;
    79вҶ’volatile uint8_t enc2_last_state = 0;
    80вҶ’volatile uint8_t enc3_last_state = 0;
    81вҶ’
    82вҶ’// м ҲлҢҖк°’ мҳӨн”„м…Ӣ (мӣҗм җ ліҙм •мҡ©)
    83вҶ’int32_t enc1_offset = 0;
    84вҶ’int32_t enc2_offset = 0;
    85вҶ’int32_t enc3_offset = 0;
    86вҶ’
    87вҶ’// м—”мҪ”лҚ” нҷңм„ұнҷ” мғҒнғң (true = мӮ¬мҡ©, false = лҜёмӮ¬мҡ©)
    88вҶ’bool enc1_enabled = true;
    89вҶ’bool enc2_enabled = true;
    90вҶ’bool enc3_enabled = true;
    91вҶ’
    92вҶ’// м ҖмһҘлҗң мң„м№ҳл“Ө [мң„м№ҳлІҲнҳё][enc1, enc2, enc3]
    93вҶ’int32_t saved_positions[MAX_POSITIONS][MAX_ENCODERS];
    94вҶ’
    95вҶ’// нғҖмқҙл°Қ
    96вҶ’unsigned long last_update_time = 0;
    97вҶ’unsigned long start_time = 0;
    98вҶ’
    99вҶ’// мӢңлҰ¬м–ј мҲҳмӢ  лІ„нҚј
   100вҶ’String serial_buffer = "";
   101вҶ’
   102вҶ’// NVS м ҖмһҘмҶҢ
   103вҶ’Preferences preferences;
   104вҶ’
   105вҶ’// ============================================================
   106вҶ’// мҝјл“ңлҹ¬мІҳ л””мҪ”л”© н…Ңмқҙлё”
   107вҶ’// ============================================================
   108вҶ’const int8_t QUAD_TABLE[4][4] = {
   109вҶ’  {   0,  +1,  -1,   0 },
   110вҶ’  {  -1,   0,   0,  +1 },
   111вҶ’  {  +1,   0,   0,  -1 },
   112вҶ’  {   0,  -1,  +1,   0 }
   113вҶ’};
   114вҶ’
   115вҶ’// ============================================================
   116вҶ’// мқён„°лҹҪнҠё н•ёл“Өлҹ¬ - Encoder 1
   117вҶ’// ============================================================
   118вҶ’void IRAM_ATTR enc1_isr() {
   119вҶ’  uint8_t a = digitalRead(ENC1_PIN_A);
   120вҶ’  uint8_t b = digitalRead(ENC1_PIN_B);
   121вҶ’  uint8_t current_state = (b << 1) | a;
   122вҶ’  
   123вҶ’  enc1_count += QUAD_TABLE[enc1_last_state][current_state];
   124вҶ’  enc1_last_state = current_state;
   125вҶ’}
   126вҶ’
   127вҶ’// ============================================================
   128вҶ’// мқён„°лҹҪнҠё н•ёл“Өлҹ¬ - Encoder 2
   129вҶ’// ============================================================
   130вҶ’void IRAM_ATTR enc2_isr() {
   131вҶ’  uint8_t a = digitalRead(ENC2_PIN_A);
   132вҶ’  uint8_t b = digitalRead(ENC2_PIN_B);
   133вҶ’  uint8_t current_state = (b << 1) | a;
   134вҶ’  
   135вҶ’  enc2_count += QUAD_TABLE[enc2_last_state][current_state];
   136вҶ’  enc2_last_state = current_state;
   137вҶ’}
   138вҶ’
   139вҶ’// ============================================================
   140вҶ’// мқён„°лҹҪнҠё н•ёл“Өлҹ¬ - Encoder 3
   141вҶ’// ============================================================
   142вҶ’void IRAM_ATTR enc3_isr() {
   143вҶ’  uint8_t a = digitalRead(ENC3_PIN_A);
   144вҶ’  uint8_t b = digitalRead(ENC3_PIN_B);
   145вҶ’  uint8_t current_state = (b << 1) | a;
   146вҶ’  
   147вҶ’  enc3_count += QUAD_TABLE[enc3_last_state][current_state];
   148вҶ’  enc3_last_state = current_state;
   149вҶ’}
   150вҶ’
   151вҶ’// ============================================================
   152вҶ’// м ҲлҢҖ м№ҙмҡҙнҠё (мҳӨн”„м…Ӣ м Ғмҡ©)
   153вҶ’// ============================================================
   154вҶ’int32_t getAbsoluteCount1() {
   155вҶ’  return enc1_count - enc1_offset;
   156вҶ’}
   157вҶ’
   158вҶ’int32_t getAbsoluteCount2() {
   159вҶ’  return enc2_count - enc2_offset;
   160вҶ’}
   161вҶ’
   162вҶ’int32_t getAbsoluteCount3() {
   163вҶ’  return enc3_count - enc3_offset;
   164вҶ’}
   165вҶ’
   166вҶ’// ============================================================
   167вҶ’// м№ҙмҡҙнҠё -> к°ҒлҸ„ ліҖнҷҳ (0~360лҸ„)
   168вҶ’// ============================================================
   169вҶ’float countToDegree(int32_t count) {
   170вҶ’  int32_t count_mod = ((count % COUNTS_PER_REV) + COUNTS_PER_REV) % COUNTS_PER_REV;
   171вҶ’  return (float)count_mod / COUNTS_PER_REV * 360.0f;
   172вҶ’}
   173вҶ’
   174вҶ’// ============================================================
   175вҶ’// NVSм—җ мҳӨн”„м…Ӣ м ҖмһҘ
   176вҶ’// ============================================================
   177вҶ’void saveOffsets() {
   178вҶ’  preferences.begin("encoder", false);
   179вҶ’  preferences.putInt("e1_offset", enc1_offset);
   180вҶ’  preferences.putInt("e2_offset", enc2_offset);
   181вҶ’  preferences.putInt("e3_offset", enc3_offset);
   182вҶ’  preferences.end();
   183вҶ’}
   184вҶ’
   185вҶ’// ============================================================
   186вҶ’// NVSм—җм„ң мҳӨн”„м…Ӣ л¶Ҳлҹ¬мҳӨкё°
   187вҶ’// ============================================================
   188вҶ’void loadOffsets() {
   189вҶ’  preferences.begin("encoder", true);
   190вҶ’  enc1_offset = preferences.getInt("e1_offset", 0);
   191вҶ’  enc2_offset = preferences.getInt("e2_offset", 0);
   192вҶ’  enc3_offset = preferences.getInt("e3_offset", 0);
   193вҶ’  preferences.end();
   194вҶ’}
   195вҶ’
   196вҶ’// ============================================================
   197вҶ’// NVSм—җ нҷңм„ұнҷ” мғҒнғң м ҖмһҘ
   198вҶ’// ============================================================
   199вҶ’void saveEnabledState() {
   200вҶ’  preferences.begin("encoder", false);
   201вҶ’  preferences.putBool("e1_en", enc1_enabled);
   202вҶ’  preferences.putBool("e2_en", enc2_enabled);
   203вҶ’  preferences.putBool("e3_en", enc3_enabled);
   204вҶ’  preferences.end();
   205вҶ’}
   206вҶ’
   207вҶ’// ============================================================
   208вҶ’// NVSм—җм„ң нҷңм„ұнҷ” мғҒнғң л¶Ҳлҹ¬мҳӨкё°
   209вҶ’// ============================================================
   210вҶ’void loadEnabledState() {
   211вҶ’  preferences.begin("encoder", true);
   212вҶ’  enc1_enabled = preferences.getBool("e1_en", true);
   213вҶ’  enc2_enabled = preferences.getBool("e2_en", true);
   214вҶ’  enc3_enabled = preferences.getBool("e3_en", true);
   215вҶ’  preferences.end();
   216вҶ’}
   217вҶ’
   218вҶ’// ============================================================
   219вҶ’// мң„м№ҳ м ҖмһҘ
   220вҶ’// ============================================================
   221вҶ’void savePosition(int pos) {
   222вҶ’  if (pos < 1 || pos > MAX_POSITIONS) return;
   223вҶ’  
   224вҶ’  int idx = pos - 1;
   225вҶ’  saved_positions[idx][0] = getAbsoluteCount1();
   226вҶ’  saved_positions[idx][1] = getAbsoluteCount2();
   227вҶ’  saved_positions[idx][2] = getAbsoluteCount3();
   228вҶ’  
   229вҶ’  preferences.begin("encoder", false);
   230вҶ’  String key1 = "pos" + String(pos) + "_e1";
   231вҶ’  String key2 = "pos" + String(pos) + "_e2";
   232вҶ’  String key3 = "pos" + String(pos) + "_e3";
   233вҶ’  preferences.putInt(key1.c_str(), saved_positions[idx][0]);
   234вҶ’  preferences.putInt(key2.c_str(), saved_positions[idx][1]);
   235вҶ’  preferences.putInt(key3.c_str(), saved_positions[idx][2]);
   236вҶ’  preferences.end();
   237вҶ’  
   238вҶ’  Serial.print("{\"cmd\":\"SAVE\",\"pos\":");
   239вҶ’  Serial.print(pos);
   240вҶ’  if (enc1_enabled) {
   241вҶ’    Serial.print(",\"e1\":");
   242вҶ’    Serial.print(saved_positions[idx][0]);
   243вҶ’  }
   244вҶ’  if (enc2_enabled) {
   245вҶ’    Serial.print(",\"e2\":");
   246вҶ’    Serial.print(saved_positions[idx][1]);
   247вҶ’  }
   248вҶ’  if (enc3_enabled) {
   249вҶ’    Serial.print(",\"e3\":");
   250вҶ’    Serial.print(saved_positions[idx][2]);
   251вҶ’  }
   252вҶ’  Serial.println(",\"ok\":true}");
   253вҶ’}
   254вҶ’
   255вҶ’// ============================================================
   256вҶ’// м ҖмһҘлҗң мң„м№ҳ л¶Ҳлҹ¬мҳӨкё°
   257вҶ’// ============================================================
   258вҶ’void loadPositions() {
   259вҶ’  preferences.begin("encoder", true);
   260вҶ’  for (int i = 0; i < MAX_POSITIONS; i++) {
   261вҶ’    String key1 = "pos" + String(i+1) + "_e1";
   262вҶ’    String key2 = "pos" + String(i+1) + "_e2";
   263вҶ’    String key3 = "pos" + String(i+1) + "_e3";
   264вҶ’    saved_positions[i][0] = preferences.getInt(key1.c_str(), 0);
   265вҶ’    saved_positions[i][1] = preferences.getInt(key2.c_str(), 0);
   266вҶ’    saved_positions[i][2] = preferences.getInt(key3.c_str(), 0);
   267вҶ’  }
   268вҶ’  preferences.end();
   269вҶ’}
   270вҶ’
   271вҶ’// ============================================================
   272вҶ’// м ҖмһҘлҗң мң„м№ҳ м •ліҙ м „мҶЎ
   273вҶ’// ============================================================
   274вҶ’void sendPositionInfo(int pos) {
   275вҶ’  if (pos < 1 || pos > MAX_POSITIONS) return;
   276вҶ’  
   277вҶ’  int idx = pos - 1;
   278вҶ’  
   279вҶ’  Serial.print("{\"cmd\":\"POS\",\"pos\":");
   280вҶ’  Serial.print(pos);
   281вҶ’  
   282вҶ’  if (enc1_enabled) {
   283вҶ’    float deg1 = countToDegree(saved_positions[idx][0]);
   284вҶ’    Serial.print(",\"e1\":{\"cnt\":");
   285вҶ’    Serial.print(saved_positions[idx][0]);
   286вҶ’    Serial.print(",\"deg\":");
   287вҶ’    Serial.print(deg1, 1);
   288вҶ’    Serial.print("}");
   289вҶ’  }
   290вҶ’  
   291вҶ’  if (enc2_enabled) {
   292вҶ’    float deg2 = countToDegree(saved_positions[idx][1]);
   293вҶ’    Serial.print(",\"e2\":{\"cnt\":");
   294вҶ’    Serial.print(saved_positions[idx][1]);
   295вҶ’    Serial.print(",\"deg\":");
   296вҶ’    Serial.print(deg2, 1);
   297вҶ’    Serial.print("}");
   298вҶ’  }
   299вҶ’  
   300вҶ’  if (enc3_enabled) {
   301вҶ’    float deg3 = countToDegree(saved_positions[idx][2]);
   302вҶ’    Serial.print(",\"e3\":{\"cnt\":");
   303вҶ’    Serial.print(saved_positions[idx][2]);
   304вҶ’    Serial.print(",\"deg\":");
   305вҶ’    Serial.print(deg3, 1);
   306вҶ’    Serial.print("}");
   307вҶ’  }
   308вҶ’  
   309вҶ’  Serial.println(",\"ok\":true}");
   310вҶ’}
   311вҶ’
   312вҶ’// ============================================================
   313вҶ’// лӘЁл“  м ҖмһҘлҗң мң„м№ҳ м •ліҙ м „мҶЎ
   314вҶ’// ============================================================
   315вҶ’void sendAllPositions() {
   316вҶ’  Serial.print("{\"cmd\":\"POSITIONS\",\"data\":[");
   317вҶ’  for (int i = 0; i < MAX_POSITIONS; i++) {
   318вҶ’    if (i > 0) Serial.print(",");
   319вҶ’    Serial.print("{\"pos\":");
   320вҶ’    Serial.print(i + 1);
   321вҶ’    if (enc1_enabled) {
   322вҶ’      Serial.print(",\"e1\":");
   323вҶ’      Serial.print(saved_positions[i][0]);
   324вҶ’    }
   325вҶ’    if (enc2_enabled) {
   326вҶ’      Serial.print(",\"e2\":");
   327вҶ’      Serial.print(saved_positions[i][1]);
   328вҶ’    }
   329вҶ’    if (enc3_enabled) {
   330вҶ’      Serial.print(",\"e3\":");
   331вҶ’      Serial.print(saved_positions[i][2]);
   332вҶ’    }
   333вҶ’    Serial.print("}");
   334вҶ’  }
   335вҶ’  Serial.println("],\"ok\":true}");
   336вҶ’}
   337вҶ’
   338вҶ’// ============================================================
   339вҶ’// нҷңм„ұнҷ”лҗң м—”мҪ”лҚ” мҲҳ л°ҳнҷҳ
   340вҶ’// ============================================================
   341вҶ’int getActiveEncoderCount() {
   342вҶ’  int count = 0;
   343вҶ’  if (enc1_enabled) count++;
   344вҶ’  if (enc2_enabled) count++;
   345вҶ’  if (enc3_enabled) count++;
   346вҶ’  return count;
   347вҶ’}
   348вҶ’
   349вҶ’// ============================================================
   350вҶ’// мӢңлҰ¬м–ј лӘ…л № мІҳлҰ¬
   351вҶ’// ============================================================
   352вҶ’void processCommand(String cmd) {
   353вҶ’  cmd.trim();
   354вҶ’  cmd.toUpperCase();
   355вҶ’  
   356вҶ’  // ZERO лӘ…л №л“Ө
   357вҶ’  if (cmd == "ZERO 1" || cmd == "ZERO1") {
   358вҶ’    enc1_count = 0;
   359вҶ’    Serial.println("{\"cmd\":\"ZERO\",\"enc\":1,\"ok\":true}");
   360вҶ’  }
   361вҶ’  else if (cmd == "ZERO 2" || cmd == "ZERO2") {
   362вҶ’    enc2_count = 0;
   363вҶ’    Serial.println("{\"cmd\":\"ZERO\",\"enc\":2,\"ok\":true}");
   364вҶ’  }
   365вҶ’  else if (cmd == "ZERO 3" || cmd == "ZERO3") {
   366вҶ’    enc3_count = 0;
   367вҶ’    Serial.println("{\"cmd\":\"ZERO\",\"enc\":3,\"ok\":true}");
   368вҶ’  }
