   597вҶ’void sendEncoderData() {
   598вҶ’  noInterrupts();
   599вҶ’  int32_t cnt1 = enc1_count;
   600вҶ’  int32_t cnt2 = enc2_count;
   601вҶ’  int32_t cnt3 = enc3_count;
