   606вҶ’  int32_t abs2 = cnt2 - enc2_offset;
   607вҶ’  int32_t abs3 = cnt3 - enc3_offset;
   608вҶ’  
   609вҶ’  // нғҖмһ„мҠӨнғ¬н”„ (ms)
   610вҶ’  unsigned long timestamp = millis() - start_time;
   611вҶ’  
   612вҶ’  // JSON м¶ңл Ҙ
   613вҶ’  Serial.print("{\"t\":");
   614вҶ’  Serial.print(timestamp);
   615вҶ’  
   616вҶ’  if (enc1_enabled) {
   617вҶ’    float deg1 = countToDegree(abs1);
   618вҶ’    Serial.print(",\"e1\":{\"cnt\":");
   619вҶ’    Serial.print(abs1);
   620вҶ’    Serial.print(",\"deg\":");
   621вҶ’    Serial.print(deg1, 1);
   622вҶ’    Serial.print("}");
   623вҶ’  }
   624вҶ’  
   625вҶ’  if (enc2_enabled) {
   626вҶ’    float deg2 = countToDegree(abs2);
   627вҶ’    Serial.print(",\"e2\":{\"cnt\":");
   628вҶ’    Serial.print(abs2);
   629вҶ’    Serial.print(",\"deg\":");
   630вҶ’    Serial.print(deg2, 1);
   631вҶ’    Serial.print("}");
   632вҶ’  }
   633вҶ’  
   634вҶ’  if (enc3_enabled) {
   635вҶ’    float deg3 = countToDegree(abs3);
   636вҶ’    Serial.print(",\"e3\":{\"cnt\":");
   637вҶ’    Serial.print(abs3);
   638вҶ’    Serial.print(",\"deg\":");
   639вҶ’    Serial.print(deg3, 1);
   640вҶ’    Serial.print("}");
   641вҶ’  }
   642вҶ’  
   643вҶ’  Serial.println(",\"ok\":true}");
   644вҶ’}
