   671вҶ’  
   672вҶ’  // н•Җ м„Өм • - Encoder 1
   673вҶ’  pinMode(ENC1_PIN_A, INPUT);
   674вҶ’  pinMode(ENC1_PIN_B, INPUT);
   675вҶ’  pinMode(ENC1_PIN_Z, INPUT);
   676вҶ’  
   677вҶ’  // н•Җ м„Өм • - Encoder 2
   678вҶ’  pinMode(ENC2_PIN_A, INPUT);
   679вҶ’  pinMode(ENC2_PIN_B, INPUT);
   680вҶ’  pinMode(ENC2_PIN_Z, INPUT);
   681вҶ’  
   682вҶ’  // н•Җ м„Өм • - Encoder 3
   683вҶ’  pinMode(ENC3_PIN_A, INPUT);
   684вҶ’  pinMode(ENC3_PIN_B, INPUT);
   685вҶ’  pinMode(ENC3_PIN_Z, INPUT);
   686вҶ’  
   687вҶ’  // NVSм—җм„ң м ҖмһҘлҗң к°’ л¶Ҳлҹ¬мҳӨкё°
   688вҶ’  loadOffsets();
   689вҶ’  loadPositions();
   690вҶ’  loadEnabledState();
   691вҶ’  
   692вҶ’  // мҙҲкё° мғҒнғң мқҪкё°
   693вҶ’  enc1_last_state = (digitalRead(ENC1_PIN_B) << 1) | digitalRead(ENC1_PIN_A);
   694вҶ’  enc2_last_state = (digitalRead(ENC2_PIN_B) << 1) | digitalRead(ENC2_PIN_A);
   695вҶ’  enc3_last_state = (digitalRead(ENC3_PIN_B) << 1) | digitalRead(ENC3_PIN_A);
   696вҶ’  
   697вҶ’  // мқён„°лҹҪнҠё м„Өм • (лӘЁл“  м—”мҪ”лҚ”м—җ лҢҖн•ҙ м„Өм •, нҷңм„ұнҷ” м—¬л¶ҖмҷҖ л¬ҙкҙҖн•ҳкІҢ)
   698вҶ’  // л№„нҷңм„ұнҷ”лҗң м—”мҪ”лҚ”лҸ„ мқён„°лҹҪнҠёлҠ” мң м§Җн•ҳкі , м¶ңл Ҙл§Ң м ңм–ҙ
   699вҶ’  setupEncoder1Interrupts();
