   712вҶ’  if (enc2_enabled) { Serial.print(",\"e2_offset\":"); Serial.print(enc2_offset); }
   713вҶ’  if (enc3_enabled) { Serial.print(",\"e3_offset\":"); Serial.print(enc3_offset); }
   714вҶ’  Serial.print(",\"e1_en\":");
   715вҶ’  Serial.print(enc1_enabled ? "true" : "false");
   716вҶ’  Serial.print(",\"e2_en\":");
   717вҶ’  Serial.print(enc2_enabled ? "true" : "false");
   718вҶ’  Serial.print(",\"e3_en\":");
   719вҶ’  Serial.print(enc3_enabled ? "true" : "false");
   720вҶ’  Serial.println(",\"ok\":true}");
   721вҶ’  
   722вҶ’  delay(100);
   723вҶ’}
