   726вҶ’// л©”мқё лЈЁн”„
   727вҶ’// ============================================================
   728вҶ’void loop() {
   729вҶ’  unsigned long current_time = millis();
   730вҶ’  
   731вҶ’  // мЈјкё°м Ғ лҚ°мқҙн„° м „мҶЎ
   732вҶ’  if (current_time - last_update_time >= UPDATE_INTERVAL_MS) {
   733вҶ’    last_update_time = current_time;
   734вҶ’    sendEncoderData();
   735вҶ’  }
   736вҶ’  
   737вҶ’  // мӢңлҰ¬м–ј лӘ…л № мҲҳмӢ 
   738вҶ’  while (Serial.available() > 0) {
   739вҶ’    char c = Serial.read();
   740вҶ’    if (c == '\n' || c == '\r') {
   741вҶ’      if (serial_buffer.length() > 0) {
   742вҶ’        processCommand(serial_buffer);
   743вҶ’        serial_buffer = "";
