   211вҶ’        double t3 = theta3 * Math.PI / 180.0;
   212вҶ’
   213вҶ’        // лҲ„м Ғ к°ҒлҸ„
   214вҶ’        double sum1 = t1;
   215вҶ’        double sum2 = t1 + t2;
   216вҶ’        double sum3 = t1 + t2 + t3;
   217вҶ’
   218вҶ’        // кҙҖм Ҳ мўҢн‘ң кі„мӮ° (3R Planar - XY нҸүл©ҙ)
   219вҶ’        joints[0] = new PointF3D(0, 0, 0);  // лІ мқҙмҠӨ
   220вҶ’
   221вҶ’        // м¶•1 лҒқ (лІ мқҙмҠӨ мӨ‘мӢ¬, Zм¶• лҶ’мқҙл§Ң)
   222вҶ’        joints[1] = new PointF3D(0, 0, 20);
   223вҶ’
   224вҶ’        // м¶•1 вҶ’ м¶•2
   225вҶ’        joints[2] = new PointF3D(
   226вҶ’            L1 * Math.Cos(sum1),
   227вҶ’            L1 * Math.Sin(sum1),
   228вҶ’            20
   229вҶ’        );
   230вҶ’
   231вҶ’        // м¶•2 вҶ’ м¶•3
   232вҶ’        joints[3] = new PointF3D(
   233вҶ’            L1 * Math.Cos(sum1) + L2 * Math.Cos(sum2),
   234вҶ’            L1 * Math.Sin(sum1) + L2 * Math.Sin(sum2),
   235вҶ’            20
   236вҶ’        );
   237вҶ’
   238вҶ’        // м¶•3 вҶ’ нҲҙ
   239вҶ’        joints[4] = new PointF3D(
   240вҶ’            L1 * Math.Cos(sum1) + L2 * Math.Cos(sum2) + L3 * Math.Cos(sum3),
   241вҶ’            L1 * Math.Sin(sum1) + L2 * Math.Sin(sum2) + L3 * Math.Sin(sum3),
   242вҶ’            20
   243вҶ’        );
   244вҶ’
   245вҶ’        // кІ°кіј н‘ңмӢң
   246вҶ’        lblResult.Text = $"нҲҙ мўҢн‘ң:\nX: {joints[4].X:F2} mm\nY: {joints[4].Y:F2} mm";
   247вҶ’    }
