   249вҶ’    // 3D вҶ’ 2D нҲ¬мҳҒ (л“ұк°Ғ нҲ¬мҳҒ)
   250вҶ’    private PointF Project3D(PointF3D p, int centerX, int centerY)
   251вҶ’    {
   252вҶ’        double radX = viewAngleX * Math.PI / 180.0;
   253вҶ’        double radZ = viewAngleZ * Math.PI / 180.0;
   254вҶ’
   255вҶ’        // Zм¶• нҡҢм „ (мўҢмҡ°)
   256вҶ’        double x1 = p.X * Math.Cos(radZ) - p.Y * Math.Sin(radZ);
   257вҶ’        double y1 = p.X * Math.Sin(radZ) + p.Y * Math.Cos(radZ);
   258вҶ’        double z1 = p.Z;
   259вҶ’
   260вҶ’        // Xм¶• нҡҢм „ (мғҒн•ҳ)
   261вҶ’        double y2 = y1 * Math.Cos(radX) - z1 * Math.Sin(radX);
   262вҶ’        double z2 = y1 * Math.Sin(radX) + z1 * Math.Cos(radX);
   263вҶ’
   264вҶ’        // 2D нҲ¬мҳҒ + нҢ¬ мҳӨн”„м…Ӣ м Ғмҡ©
   265вҶ’        float screenX = (float)(centerX + x1 * zoom + panOffsetX);
   266вҶ’        float screenY = (float)(centerY - z2 * zoom + panOffsetY);
   267вҶ’
   268вҶ’        return new PointF(screenX, screenY);
   269вҶ’    }
