   291вҶ’    private void DrawGrid(Graphics g, int cx, int cy)
   292вҶ’    {
   293вҶ’        using Pen gridPen = new Pen(Color.FromArgb(60, 60, 60), 1);
   294вҶ’        int gridSize = 50;
   295вҶ’        int range = 300;
   296вҶ’
   297вҶ’        for (int i = -range; i <= range; i += gridSize)
   298вҶ’        {
   299вҶ’            // X л°©н–Ҙ м„ 
   300вҶ’            PointF p1 = Project3D(new PointF3D(i, -range, 0), cx, cy);
   301вҶ’            PointF p2 = Project3D(new PointF3D(i, range, 0), cx, cy);
   302вҶ’            g.DrawLine(gridPen, p1, p2);
   303вҶ’
   304вҶ’            // Y л°©н–Ҙ м„ 
   305вҶ’            p1 = Project3D(new PointF3D(-range, i, 0), cx, cy);
   306вҶ’            p2 = Project3D(new PointF3D(range, i, 0), cx, cy);
   307вҶ’            g.DrawLine(gridPen, p1, p2);
   308вҶ’        }
   309вҶ’    }
