   335вҶ’    private void DrawRobotArm(Graphics g, int cx, int cy)
   336вҶ’    {
   337вҶ’        // лІ мқҙмҠӨ мӣҗ
   338вҶ’        using Pen basePen = new Pen(Color.Gray, 3);
   339вҶ’        PointF baseCenter = Project3D(joints[0], cx, cy);
   340вҶ’        g.DrawEllipse(basePen, baseCenter.X - 20, baseCenter.Y - 10, 40, 20);
   341вҶ’
   342вҶ’        // л§ҒнҒ¬ мғүмғҒ
   343вҶ’        Color[] linkColors = { Color.Orange, Color.Orange, Color.Cyan, Color.Magenta };
   344вҶ’        int[] linkWidths = { 8, 6, 5, 4 };
   345вҶ’
   346вҶ’        // л§ҒнҒ¬ к·ёлҰ¬кё°
   347вҶ’        for (int i = 1; i < joints.Length; i++)
   348вҶ’        {
   349вҶ’            PointF p1 = Project3D(joints[i - 1], cx, cy);
   350вҶ’            PointF p2 = Project3D(joints[i], cx, cy);
   351вҶ’
   352вҶ’            using Pen linkPen = new Pen(linkColors[i - 1], linkWidths[i - 1]);
   353вҶ’            linkPen.StartCap = System.Drawing.Drawing2D.LineCap.Round;
   354вҶ’            linkPen.EndCap = System.Drawing.Drawing2D.LineCap.Round;
   355вҶ’            g.DrawLine(linkPen, p1, p2);
   356вҶ’        }
   357вҶ’
   358вҶ’        // кҙҖм Ҳ к·ёлҰ¬кё°
   359вҶ’        for (int i = 1; i < joints.Length; i++)
   360вҶ’        {
   361вҶ’            PointF p = Project3D(joints[i], cx, cy);
   362вҶ’            int r = (i == joints.Length - 1) ? 8 : 6;  // нҲҙмқҖ мўҖ лҚ” нҒ¬кІҢ
   363вҶ’            Color c = (i == joints.Length - 1) ? Color.Red : Color.Yellow;
   364вҶ’
   365вҶ’            using SolidBrush brush = new SolidBrush(c);
   366вҶ’            g.FillEllipse(brush, p.X - r, p.Y - r, r * 2, r * 2);
   367вҶ’            g.DrawEllipse(Pens.White, p.X - r, p.Y - r, r * 2, r * 2);
   368вҶ’        }
   369вҶ’
   370вҶ’        // нҲҙ мўҢн‘ң н…ҚмҠӨнҠё
   371вҶ’        PointF toolPos = Project3D(joints[4], cx, cy);
   372вҶ’        using Font font = new Font("Consolas", 9);
   373вҶ’        string toolText = $"({joints[4].X:F1}, {joints[4].Y:F1})";
   374вҶ’        g.DrawString(toolText, font, Brushes.White, toolPos.X + 10, toolPos.Y - 20);
   375вҶ’    }
