   378вҶ’    private void PicViewer_MouseDown(object? sender, MouseEventArgs e)
   379вҶ’    {
   380вҶ’        lastMouse = e.Location;
   381вҶ’
   382вҶ’        // мўҢмҡ° лҸҷмӢң нҒҙлҰӯ = нҢ¬ мқҙлҸҷ
   383вҶ’        if (e.Button == (MouseButtons.Left | MouseButtons.Right) ||
   384вҶ’            (e.Button == MouseButtons.Left && (Control.MouseButtons & MouseButtons.Right) != 0) ||
   385вҶ’            (e.Button == MouseButtons.Right && (Control.MouseButtons & MouseButtons.Left) != 0))
   386вҶ’        {
   387вҶ’            isPanning = true;
   388вҶ’            isDragging = false;
   389вҶ’            picViewer.Cursor = Cursors.Hand;
   390вҶ’        }
   391вҶ’        // мўҢнҒҙлҰӯл§Ң = нҡҢм „
   392вҶ’        else if (e.Button == MouseButtons.Left)
   393вҶ’        {
   394вҶ’            isDragging = true;
   395вҶ’            isPanning = false;
   396вҶ’            picViewer.Cursor = Cursors.SizeAll;
   397вҶ’        }
   398вҶ’    }
