   400вҶ’    private void PicViewer_MouseMove(object? sender, MouseEventArgs e)
   401вҶ’    {
   402вҶ’        int dx = e.X - lastMouse.X;
   403вҶ’        int dy = e.Y - lastMouse.Y;
   404вҶ’
   405вҶ’        // нҢ¬ мқҙлҸҷ (мўҢмҡ° лҸҷмӢң нҒҙлҰӯ)
   406вҶ’        if (isPanning)
   407вҶ’        {
   408вҶ’            panOffsetX += dx;
   409вҶ’            panOffsetY += dy;
   410вҶ’            lastMouse = e.Location;
   411вҶ’            picViewer.Invalidate();
   412вҶ’        }
   413вҶ’        // нҡҢм „ (мўҢнҒҙлҰӯ)
   414вҶ’        else if (isDragging)
   415вҶ’        {
   416вҶ’            viewAngleZ += dx * 0.5;
   417вҶ’            viewAngleX += dy * 0.5;
   418вҶ’
   419вҶ’            // мғҒн•ҳ к°ҒлҸ„ м ңн•ң
   420вҶ’            viewAngleX = Math.Max(-90, Math.Min(90, viewAngleX));
   421вҶ’
   422вҶ’            lastMouse = e.Location;
   423вҶ’            picViewer.Invalidate();
   424вҶ’        }
   425вҶ’    }
