   427вҶ’    private void PicViewer_MouseUp(object? sender, MouseEventArgs e)
   428вҶ’    {
   429вҶ’        // л‘ҳ лӢӨ л–јл©ҙ л“ңлһҳк·ё мў…лЈҢ
   430вҶ’        if ((Control.MouseButtons & MouseButtons.Left) == 0 &&
   431вҶ’            (Control.MouseButtons & MouseButtons.Right) == 0)
   432вҶ’        {
   433вҶ’            isDragging = false;
   434вҶ’            isPanning = false;
   435вҶ’            picViewer.Cursor = Cursors.Default;
   436вҶ’        }
   437вҶ’    }
